class Solution {
    public String countOfAtoms(String formula) {
        Map<String, Integer> count = new HashMap<>();
        Stack<Map<String, Integer>> stack = new Stack<>();
        int i = 0;
        while (i < formula.length()) {
            if (Character.isUpperCase(formula.charAt(i))) {
                String atom = "";
                while (i < formula.length() && Character.isLetterOrDigit(formula.charAt(i))) {
                    atom += formula.charAt(i++);
                }
                if (i < formula.length() && formula.charAt(i) == '(') {
                    stack.push(new HashMap<>(count));
                    i++;
                } else {
                    count.put(atom, count.getOrDefault(atom, 0) + 1);
                }
            } else if (Character.isDigit(formula.charAt(i))) {
                int j = i;
                while (j < formula.length() && Character.isDigit(formula.charAt(j))) {
                    j++;
                }
                count.put(formula.substring(i, j), count.getOrDefault(formula.substring(i, j), 0) + Integer.parseInt(formula.substring(i, j)));
                i = j;
            } else {
                i++;
            }
        }
        while (!stack.isEmpty()) {
            Map<String, Integer> temp = stack.pop();
            for (String atom : temp.keySet()) {
                count.put(atom, count.getOrDefault(atom, 0) + temp.get(atom));
            }
        }
        StringBuilder sb = new StringBuilder();
        List<String> atoms = new ArrayList<>(count.keySet());
        Collections.sort(atoms);
        for (String atom : atoms) {
            sb.append(atom);
            if (count.get(atom) > 1) {
                sb.append(count.get(atom));
            }
        }
        return sb.toString();
    }
}
